        "Commander Access": "Commander access",
        "Complete MIT Pro experience for active users.": "\u062a\u062c\u0631\u0628\u0629 MIT Pro \u0643\u0627\u0645\u0644\u0629 \u0644\u0644\u0645\u0633\u062a\u062e\u062f\u0645\u064a\u0646 \u0627\u0644\u0646\u0634\u0637\u064a\u0646.",
        "Advanced tools": "\u0623\u062f\u0648\u0627\u062a \u0645\u062a\u0642\u062f\u0645\u0629",
        "Timing sync": "\u0645\u0632\u0627\u0645\u0646\u0629 \u0627\u0644\u062a\u0648\u0642\u064a\u062a",
