        "Full command": "\u0627\u0644\u0623\u0645\u0631 \u0627\u0644\u0643\u0627\u0645\u0644",
        "Supreme Access": "Supreme access",
        "Full command center access and advanced coverage.": "\u0627\u0644\u0648\u0635\u0648\u0644 \u0627\u0644\u0643\u0627\u0645\u0644 \u0625\u0644\u0649 \u0645\u0631\u0643\u0632 \u0627\u0644\u0642\u064a\u0627\u062f\u0629 \u0648\u0627\u0644\u062a\u063a\u0637\u064a\u0629 \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u0629.",
        "Advanced OTC suite": "\u0645\u062c\u0645\u0648\u0639\u0629 OTC \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u0629",
        "Full battlefield": "\u0633\u0627\u062d\u0629 \u0627\u0644\u0645\u0639\u0631\u0643\u0629 \u0643\u0627\u0645\u0644\u0629",
        "Future priority access": "\u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0627\u0644\u0623\u0648\u0644\u0648\u064a\u0629 \u0641\u064a \u0627\u0644\u0645\u0633\u062a\u0642\u0628\u0644",
        "View Supreme": "\u0639\u0631\u0636 \u0627\u0644\u0639\u0644\u064a\u0627",
