        "The MIT PRO Promise": "\u0648\u0639\u062f \u0645\u0639\u0647\u062f \u0645\u0627\u0633\u0627\u062a\u0634\u0648\u0633\u062a\u0633 \u0644\u0644\u062a\u0643\u0646\u0648\u0644\u0648\u062c\u064a\u0627 \u0644\u0644\u0645\u062d\u062a\u0631\u0641\u064a\u0646",
        "We do not promise outcomes.": "\u0646\u062d\u0646 \u0644\u0627 \u0646\u0639\u062f \u0628\u0627\u0644\u0646\u062a\u0627\u0626\u062c.",
