        "Understand": "\u064a\u0641\u0647\u0645",
        "Market behavior translated into clear intelligence.": "\u0633\u0644\u0648\u0643 \u0627\u0644\u0633\u0648\u0642 \u064a\u062a\u0631\u062c\u0645 \u0625\u0644\u0649 \u0627\u0633\u062a\u062e\u0628\u0627\u0631\u0627\u062a \u0648\u0627\u0636\u062d\u0629.",
        "Recognize Risk": "\u0627\u0644\u062a\u0639\u0631\u0641 \u0639\u0644\u0649 \u0627\u0644\u0645\u062e\u0627\u0637\u0631",
