        "OTC market access": "\u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0627\u0644\u0623\u0633\u0648\u0627\u0642 \u062e\u0627\u0631\u062c \u0627\u0644\u0628\u0648\u0631\u0635\u0629",
