        "Advanced REAL strategies": "\u0627\u0633\u062a\u0631\u0627\u062a\u064a\u062c\u064a\u0627\u062a \u062d\u0642\u064a\u0642\u064a\u0629 \u0645\u062a\u0642\u062f\u0645\u0629",
        "OTC trap suite": "\u062c\u0646\u0627\u062d \u0641\u062e OTC",
